(function(){
 var DICT=window.I18N, DEF="bm", RTL={ar:1}, LBL={en:"EN",bm:"BM",zh:"中文",ta:"தமிழ்",ar:"عربي"};
 function t(l,k){return (DICT[l]&&DICT[l][k]!=null)?DICT[l][k]:(DICT.en[k]!=null?DICT.en[k]:k);}
 window.AF_LANG=DEF;
 window.AF_t=function(k){return t(window.AF_LANG||DEF,k);};
 function apply(l){
  if(!DICT[l])l=DEF; window.AF_LANG=l;
  var H=document.documentElement; H.setAttribute("lang",l); H.setAttribute("dir",RTL[l]?"rtl":"ltr");
  document.querySelectorAll("[data-i18n]").forEach(function(e){e.innerHTML=t(l,e.getAttribute("data-i18n"));});
  document.querySelectorAll("[data-i18n-ph]").forEach(function(e){e.setAttribute("placeholder",t(l,e.getAttribute("data-i18n-ph")).replace(/&amp;/g,"&"));});
  document.querySelectorAll(".js-wa").forEach(function(a){a.setAttribute("href","https://wa.me/"+window.WA_NUMBER+"?text="+encodeURIComponent(t(l,"wa.msg").replace(/&amp;/g,"&")));});
  document.querySelectorAll(".lang__cur").forEach(function(e){e.textContent=LBL[l]||l.toUpperCase();});
  document.querySelectorAll(".lang__menu button[data-lang]").forEach(function(b){b.classList.toggle("on",b.getAttribute("data-lang")===l);});
  try{localStorage.setItem("af-lang",l);}catch(e){}
  document.dispatchEvent(new CustomEvent("af:lang",{detail:{lang:l}}));
 }
 window.AF_setLang=apply;
 document.addEventListener("DOMContentLoaded",function(){
  var saved=DEF; try{saved=localStorage.getItem("af-lang")||DEF;}catch(e){}
  apply(saved);
  document.querySelectorAll(".lang").forEach(function(w){var b=w.querySelector(".lang__btn"); if(b)b.addEventListener("click",function(e){e.stopPropagation();w.classList.toggle("open");});});
  document.querySelectorAll(".lang__menu button[data-lang]").forEach(function(b){b.addEventListener("click",function(){apply(b.getAttribute("data-lang"));document.querySelectorAll(".lang.open").forEach(function(w){w.classList.remove("open");});});});
  var mt=document.querySelector(".navtoggle"); if(mt)mt.addEventListener("click",function(e){e.stopPropagation();document.body.classList.toggle("nav-open");});
  document.querySelectorAll(".navlinks a").forEach(function(a){a.addEventListener("click",function(){document.body.classList.remove("nav-open");});});
  document.addEventListener("click",function(){document.querySelectorAll(".lang.open").forEach(function(w){w.classList.remove("open");});document.body.classList.remove("nav-open");});
 });
})();
